// MARK: - Analytics Tracker for Deep Links

class DeepLinkAnalytics {
    
    enum Source: String {
        case marketingCampaign = "marketing_campaign"
        case emailNotification = "email_notification"
        case pushNotification = "push_notification"
        case unknown = "unknown"
    }
    
    static func trackDeepLink(url: URL, route: DeepLinkRoute) {
        let source = extractSource(from: url)
        let campaignID = extractCampaignID(from: url)
        
        var eventParams: [String: String] = [
            "url": url.absoluteString,
            "source": source.rawValue,
            "route": routeName(for: route)
        ]
        
        if let campaignID = campaignID {
            eventParams["campaign_id"] = campaignID
        }
        
        print("DeepLink Analytics Event: \(eventParams)")
        // Send to your analytics service (Firebase, Mixpanel, etc.)
    }
    
    private static func extractSource(from url: URL) -> Source {
        guard let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems else {
            return .unknown
        }
        
        if let sourceValue = queryItems.first(where: { $0.name == "utm_source" })?.value {
            switch sourceValue {
            case "marketing", "campaign":
                return .marketingCampaign
            case "email":
                return .emailNotification
            case "push":
                return .pushNotification
            default:
                return .unknown
            }
        }
        
        return .unknown
    }
    
    private static func extractCampaignID(from url: URL) -> String? {
        let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems
        return queryItems?.first(where: { $0.name == "campaign_id" })?.value
    }
    
    private static func routeName(for route: DeepLinkRoute) -> String {
        switch route {
        case .profile: return "profile"
        case .paymentConfirm: return "payment_confirm"
        case .adminSettings: return "admin_settings"
        case .unknown: return "unknown"
        }
    }
}

// MARK: - Deferred Deep Link Handler

class DeferredDeepLinkHandler {
    
    private static let pendingDeepLinkKey = "pendingDeepLink"
    
    static func savePendingDeepLink(url: URL) {
        UserDefaults.standard.set(url.absoluteString, forKey: pendingDeepLinkKey)
    }
    
    static func consumePendingDeepLink() -> URL? {
        guard let urlString = UserDefaults.standard.string(forKey: pendingDeepLinkKey),
              let url = URL(string: urlString) else {
            return nil
        }
        UserDefaults.standard.removeObject(forKey: pendingDeepLinkKey)
        return url
    }
}

